// ============================================
// NORMALIZAR DATOS DE CONTACTOS
// ============================================
// Mapea columnas ES/EN, limpia y valida datos.
// El mapeo de columnas viene de config/mapping.json.
// Si se necesita agregar sinónimos, editar COLUMN_MAP.
// ============================================

const COLUMN_MAP = {
  'email': 'email',
  'correo': 'email',
  'e-mail': 'email',
  'correo electrónico': 'email',
  'correo electronico': 'email',
  'nombre': 'nombre',
  'fname': 'nombre',
  'first name': 'nombre',
  'first_name': 'nombre',
  'primer nombre': 'nombre',
  'apellido': 'apellido',
  'lname': 'apellido',
  'last name': 'apellido',
  'last_name': 'apellido',
  'telefono': 'telefono',
  'teléfono': 'telefono',
  'phone': 'telefono',
  'tel': 'telefono',
  'celular': 'telefono',
  'móvil': 'telefono',
  'movil': 'telefono',
  'empresa': 'empresa',
  'company': 'empresa',
  'organización': 'empresa',
  'organizacion': 'empresa',
  'organization': 'empresa',
  'cargo': 'cargo',
  'puesto': 'cargo',
  'position': 'cargo',
  'job title': 'cargo',
  'job_title': 'cargo',
  'title': 'cargo',
  'rol': 'cargo',
  'origen': 'origen',
  'source': 'origen',
  'fuente': 'origen',
  'canal': 'origen',
  'ultimo contacto': 'ultimo_contacto',
  'último contacto': 'ultimo_contacto',
  'last contact': 'ultimo_contacto',
  'last_contact': 'ultimo_contacto',
  'fecha contacto': 'ultimo_contacto',
  'fecha_contacto': 'ultimo_contacto',
  'interacciones': 'interacciones',
  'interactions': 'interacciones',
  'contactos': 'interacciones',
  'touches': 'interacciones',
  'estado': 'estado',
  'status': 'estado',
  'activo': 'estado',
  'notas': 'notas',
  'notes': 'notas',
  'comentarios': 'notas',
  'observaciones': 'notas'
};

const ESTADO_ACTIVO = ['activo', 'active', 'si', 'sí', 'yes', '1', 'true'];

function capitalize(str) {
  if (!str) return '';
  return str.charAt(0).toUpperCase() + str.slice(1).toLowerCase();
}

function parseDate(val) {
  if (!val) return null;
  const d = new Date(val);
  return isNaN(d.getTime()) ? null : d.toISOString();
}

function cleanPhone(val) {
  if (!val) return '';
  return String(val).replace(/[^0-9+\-\s()]/g, '').trim();
}

const results = [];

for (const item of $input.all()) {
  const raw = item.json;
  const normalized = {};

  // Mapear columnas dinámicamente
  for (const [key, value] of Object.entries(raw)) {
    const normalizedKey = key.toLowerCase().trim();
    const mappedKey = COLUMN_MAP[normalizedKey];
    if (mappedKey) {
      normalized[mappedKey] = typeof value === 'string' ? value.trim() : value;
    }
  }

  // Validar email (campo obligatorio)
  normalized.email = (normalized.email || '').toLowerCase().trim();
  if (!normalized.email || !normalized.email.includes('@')) {
    normalized._valid = false;
    normalized._motivo_descarte = 'Email inválido o vacío';
  } else {
    normalized._valid = true;
  }

  // Limpiar nombre y apellido
  normalized.nombre = capitalize(normalized.nombre || '');
  normalized.apellido = capitalize(normalized.apellido || '');

  // Limpiar teléfono
  normalized.telefono = cleanPhone(normalized.telefono);

  // Normalizar estado
  const estado = (normalized.estado || '').toLowerCase().trim();
  normalized.estado = ESTADO_ACTIVO.includes(estado) ? 'activo' : 'inactivo';

  // Parsear interacciones a número
  normalized.interacciones = parseInt(normalized.interacciones) || 0;

  // Normalizar origen
  normalized.origen = (normalized.origen || 'desconocido').toLowerCase().trim();

  // Parsear fecha de último contacto
  normalized.ultimo_contacto = parseDate(normalized.ultimo_contacto);

  // Normalizar cargo
  normalized.cargo = (normalized.cargo || '').toLowerCase().trim();

  // Empresa
  normalized.empresa = (normalized.empresa || '').trim();

  // Notas
  normalized.notas = (normalized.notas || '').trim();

  // Índice para referencia en Sheet update
  normalized._row_number = item.json.row_number || (results.length + 2);

  results.push({ json: normalized });
}

return results;

// ============================================
// CALCULAR SCORE DE CADA CONTACTO
// ============================================
// Sistema de scoring modular y editable.
// Para modificar reglas: editar las constantes.
// Para agregar criterios: agregar bloque nuevo.
// ============================================

// --- REGLAS DE SCORING (EDITAR AQUÍ) ---
const RULES = {
  recencia: { dias_7: 30, dias_14: 20, dias_30: 10, dias_60: 5, mas_60: 0 },
  interacciones: { mas_de_5: 25, entre_3_y_5: 20, entre_1_y_2: 10, ninguna: 0 },
  origen: {
    referido: 15, evento: 12, web: 8,
    'red social': 6, linkedin: 6, otro: 3, desconocido: 0
  },
  cargo: { alto: 15, medio: 10, bajo: 5, sin_dato: 0 },
  penalizaciones: {
    inactivo: -20, sin_telefono: -10,
    sin_empresa: -5, sin_nombre: -5
  }
};

// --- CARGOS POR NIVEL ---
const CARGOS_ALTO = [
  'dueño', 'dueña', 'director', 'directora', 'ceo',
  'gerente general', 'fundador', 'fundadora', 'owner',
  'presidente', 'presidenta', 'socio', 'socia', 'cto', 'cfo', 'coo'
];
const CARGOS_MEDIO = [
  'gerente', 'jefe', 'jefa', 'responsable',
  'encargado', 'encargada', 'manager', 'lead',
  'head', 'supervisor', 'supervisora'
];
const CARGOS_BAJO = [
  'coordinador', 'coordinadora', 'analista', 'asistente',
  'ejecutivo', 'ejecutiva', 'vendedor', 'vendedora',
  'asesor', 'asesora'
];

const now = new Date();
const results = [];

for (const item of $input.all()) {
  const c = item.json;

  // Contactos inválidos → score 0
  if (!c._valid) {
    results.push({
      json: {
        ...c,
        score: 0,
        score_detalle: { motivo: c._motivo_descarte }
      }
    });
    continue;
  }

  let score = 0;
  const detalle = {};

  // 1. RECENCIA
  if (c.ultimo_contacto) {
    const diffDays = Math.floor(
      (now - new Date(c.ultimo_contacto)) / (1000 * 60 * 60 * 24)
    );
    if (diffDays <= 7) {
      score += RULES.recencia.dias_7;
      detalle.recencia = `+${RULES.recencia.dias_7} (${diffDays}d)`;
    } else if (diffDays <= 14) {
      score += RULES.recencia.dias_14;
      detalle.recencia = `+${RULES.recencia.dias_14} (${diffDays}d)`;
    } else if (diffDays <= 30) {
      score += RULES.recencia.dias_30;
      detalle.recencia = `+${RULES.recencia.dias_30} (${diffDays}d)`;
    } else if (diffDays <= 60) {
      score += RULES.recencia.dias_60;
      detalle.recencia = `+${RULES.recencia.dias_60} (${diffDays}d)`;
    } else {
      detalle.recencia = `+0 (${diffDays}d - antiguo)`;
    }
  } else {
    detalle.recencia = '+0 (sin fecha)';
  }

  // 2. INTERACCIONES
  const inter = c.interacciones;
  if (inter > 5) {
    score += RULES.interacciones.mas_de_5;
    detalle.interacciones = `+${RULES.interacciones.mas_de_5} (${inter})`;
  } else if (inter >= 3) {
    score += RULES.interacciones.entre_3_y_5;
    detalle.interacciones = `+${RULES.interacciones.entre_3_y_5} (${inter})`;
  } else if (inter >= 1) {
    score += RULES.interacciones.entre_1_y_2;
    detalle.interacciones = `+${RULES.interacciones.entre_1_y_2} (${inter})`;
  } else {
    detalle.interacciones = '+0 (sin interacciones)';
  }

  // 3. ORIGEN
  const origenScore = RULES.origen[c.origen] ?? RULES.origen.otro;
  score += origenScore;
  detalle.origen = `+${origenScore} (${c.origen})`;

  // 4. CARGO
  const cargo = c.cargo;
  if (CARGOS_ALTO.some(t => cargo.includes(t))) {
    score += RULES.cargo.alto;
    detalle.cargo = `+${RULES.cargo.alto} (alto: ${cargo})`;
  } else if (CARGOS_MEDIO.some(t => cargo.includes(t))) {
    score += RULES.cargo.medio;
    detalle.cargo = `+${RULES.cargo.medio} (medio: ${cargo})`;
  } else if (CARGOS_BAJO.some(t => cargo.includes(t))) {
    score += RULES.cargo.bajo;
    detalle.cargo = `+${RULES.cargo.bajo} (bajo: ${cargo})`;
  } else {
    detalle.cargo = '+0 (no clasificado)';
  }

  // 5. PENALIZACIONES
  if (c.estado === 'inactivo') {
    score += RULES.penalizaciones.inactivo;
    detalle.pen_estado = `${RULES.penalizaciones.inactivo} (inactivo)`;
  }
  if (!c.telefono) {
    score += RULES.penalizaciones.sin_telefono;
    detalle.pen_telefono = `${RULES.penalizaciones.sin_telefono} (sin tel)`;
  }
  if (!c.empresa) {
    score += RULES.penalizaciones.sin_empresa;
    detalle.pen_empresa = `${RULES.penalizaciones.sin_empresa} (sin empresa)`;
  }
  if (!c.nombre) {
    score += RULES.penalizaciones.sin_nombre;
    detalle.pen_nombre = `${RULES.penalizaciones.sin_nombre} (sin nombre)`;
  }

  // Score mínimo 0
  score = Math.max(0, score);

  results.push({
    json: { ...c, score, score_detalle: detalle }
  });
}

return results;

// ============================================
// CLASIFICAR LEADS POR SCORE
// ============================================
// Asigna categoría y label basado en umbrales.
// Para ajustar umbrales, editar THRESHOLDS.
// ============================================

const THRESHOLDS = {
  HOT: 60,
  WARM: 35,
  COLD: 15
};

const now = new Date().toISOString();
const results = [];

for (const item of $input.all()) {
  const c = item.json;
  const score = c.score || 0;

  let score_label, categoria;

  if (!c._valid) {
    score_label = 'NONE';
    categoria = 'DESCARTADO';
  } else if (score >= THRESHOLDS.HOT) {
    score_label = 'HIGH';
    categoria = 'HOT';
  } else if (score >= THRESHOLDS.WARM) {
    score_label = 'MEDIUM';
    categoria = 'WARM';
  } else if (score >= THRESHOLDS.COLD) {
    score_label = 'LOW';
    categoria = 'COLD';
  } else {
    score_label = 'NONE';
    categoria = 'DESCARTADO';
  }

  results.push({
    json: {
      ...c,
      score_label,
      categoria,
      fecha_procesamiento: now
    }
  });
}

return results;

// ============================================
// COMPARAR CONTACTOS CON MAILCHIMP
// ============================================
// Determina acción por contacto:
// - 'crear': no existe en Mailchimp
// - 'actualizar': existe pero tiene cambios
// - 'ignorar': existe sin cambios o descartado
// ============================================

// Miembros actuales de Mailchimp (input directo)
const mcMembers = $input.all();

// Contactos clasificados (del nodo anterior via referencia)
const contacts = $('Clasificar Leads').all();

// Lookup por email
const mcLookup = {};
for (const m of mcMembers) {
  const email = (m.json.email_address || '').toLowerCase();
  if (email) {
    mcLookup[email] = {
      status: m.json.status,
      merge_fields: m.json.merge_fields || {},
      tags: (m.json.tags || []).map(t => t.name || t),
      id: m.json.id
    };
  }
}

function hasChanges(contact, mc) {
  // Comparar merge fields clave
  if ((mc.merge_fields.FNAME || '') !== contact.nombre) return true;
  if ((mc.merge_fields.LNAME || '') !== contact.apellido) return true;
  if ((mc.merge_fields.PHONE || '') !== contact.telefono) return true;

  // Comparar tag de categoría
  const currentTags = mc.tags.map(t => t.toUpperCase());
  if (!currentTags.includes(contact.categoria)) return true;

  return false;
}

const results = [];

for (const item of contacts) {
  const c = item.json;

  // Descartar contactos inválidos
  if (!c._valid || c.categoria === 'DESCARTADO') {
    results.push({ json: { ...c, _accion: 'ignorar', _motivo: 'descartado' } });
    continue;
  }

  const mc = mcLookup[c.email];

  if (!mc) {
    // No existe en Mailchimp → crear
    results.push({ json: { ...c, _accion: 'crear', _mc_status: null } });
  } else if (mc.status === 'unsubscribed' || mc.status === 'cleaned') {
    // Respetar unsubscribed/cleaned → no tocar
    results.push({
      json: { ...c, _accion: 'ignorar', _motivo: `mc_status=${mc.status}`, _mc_status: mc.status }
    });
  } else if (hasChanges(c, mc)) {
    // Existe con cambios → actualizar
    results.push({ json: { ...c, _accion: 'actualizar', _mc_status: mc.status, _mc_id: mc.id } });
  } else {
    // Sin cambios → ignorar
    results.push({ json: { ...c, _accion: 'ignorar', _motivo: 'sin_cambios', _mc_status: mc.status } });
  }
}

return results;

// ============================================
// FILTRAR PARA TAGGING
// ============================================
// Solo enviar a tags los contactos que fueron
// creados o actualizados (no ignorados/descartados)
// y generar el hash MD5 necesario para la API.
// ============================================

const crypto = require('crypto');

const results = [];

for (const item of $input.all()) {
  const c = item.json;

  // Solo taggear si fue creado o actualizado
  if (c._accion === 'crear' || c._accion === 'actualizar') {
    const emailHash = crypto
      .createHash('md5')
      .update(c.email.toLowerCase().trim())
      .digest('hex');

    results.push({
      json: {
        ...c,
        _email_hash: emailHash
      }
    });
  }
}

// Si no hay contactos para taggear, pasar vacío
if (results.length === 0) {
  results.push({ json: { _skip_tags: true } });
}

return results;

// ============================================
// GENERAR REPORTE FINAL
// ============================================
// Resumen de ejecución con conteos por categoría
// y detalle de acciones realizadas.
// ============================================

const allItems = $('Comparar y Decidir').all();

const stats = {
  total_procesados: allItems.length,
  validos: 0,
  invalidos: 0,
  hot: 0,
  warm: 0,
  cold: 0,
  descartados: 0,
  creados_en_mc: 0,
  actualizados_en_mc: 0,
  ignorados: 0,
  respetados_unsub: 0
};

const hotLeads = [];

for (const item of allItems) {
  const c = item.json;

  if (c._valid) {
    stats.validos++;
  } else {
    stats.invalidos++;
  }

  switch (c.categoria) {
    case 'HOT': stats.hot++; hotLeads.push({ email: c.email, nombre: `${c.nombre} ${c.apellido}`, score: c.score, empresa: c.empresa }); break;
    case 'WARM': stats.warm++; break;
    case 'COLD': stats.cold++; break;
    case 'DESCARTADO': stats.descartados++; break;
  }

  switch (c._accion) {
    case 'crear': stats.creados_en_mc++; break;
    case 'actualizar': stats.actualizados_en_mc++; break;
    case 'ignorar':
      stats.ignorados++;
      if (c._motivo && c._motivo.startsWith('mc_status=')) stats.respetados_unsub++;
      break;
  }
}

const reporte = {
  timestamp: new Date().toISOString(),
  resumen: `Procesados: ${stats.total_procesados} | HOT: ${stats.hot} | WARM: ${stats.warm} | COLD: ${stats.cold} | Descartados: ${stats.descartados}`,
  estadisticas: stats,
  hot_leads: hotLeads,
  acciones_mailchimp: {
    creados: stats.creados_en_mc,
    actualizados: stats.actualizados_en_mc,
    ignorados: stats.ignorados,
    unsubscribed_respetados: stats.respetados_unsub
  }
};

return [{ json: reporte }];

// ============================================
// PREPARAR ITEMS PARA SHEET UPDATE
// ============================================
// Toma todos los contactos procesados y prepara
// el formato para actualizar Google Sheets.
// ============================================

const allContacts = $('Comparar y Decidir').all();
const results = [];

for (const item of allContacts) {
  const c = item.json;
  results.push({
    json: {
      email: c.email,
      score: c.score || 0,
      categoria: c.categoria || 'DESCARTADO',
      fecha_procesamiento: c.fecha_procesamiento,
      _row_number: c._row_number
    }
  });
}

return results;
